blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie poznasz <strong>Tagi pytań</strong> - krótkie pytania na końcu zdania w celu potwierdzenia informacji lub uprzejmej komunikacji.",
    "rules": [
        {
            "label": "POZYTYWNY + NEGATYWNY",
            "color": "emerald",
            "text": "<strong>Twierdzenie</strong> + przeczący tag:",
            "example": "Lubisz kawę, prawda?"
        },
        {
            "label": "NEGATYWNY + POZYTYWNY",
            "color": "blue",
            "text": "<strong>Zaprzeczenie</strong> + tag pozytywny:",
            "example": "Nie lubisz kawy, prawda? ↘ / ↗"
        },
        {
            "label": "ІНТОНАЦІЯ",
            "color": "amber",
            "text": "<strong>Падаюча</strong> — підтвердження, <strong>зростаюча</strong> — справжнє питання:",
            "example": "It's nice, isn't it? ↘ / ↗"
        }
    ]
}

{
    "title": "1. Co to są znaczniki pytań?",
    "intro": "Tagi pytań to krótkie pytania na końcu zdania:",
    "items": [
        {
            "label": "Twierdzenie",
            "title": "Ona jest szczęśliwa, prawda?",
            "subtitle": "Pozytywne + negatywne tag"
        },
        {
            "label": "Negacja",
            "title": "Ona nie jest szczęśliwa, prawda?",
            "subtitle": "Tag negatywny + pozytywny"
        },
        {
            "label": "Podstawowa zasada",
            "title": "Stwierdzenie + przeciwieństwo tag",
            "subtitle": "Forma przeciwna"
        }
    ]
}

{
    "title": "2. Tagi pytań z czasownikiem TO BE",
    "sections": [
        {
            "label": "Present Simple — AM/IS/ARE",
            "color": "emerald",
            "description": "Za pomocą <strong>to be</strong> w czasie Present Simple tworzymy tag z am/is/are:",
            "examples": [
                {
                    "en": "Ona jest szczęśliwa, prawda?",
                    "ua": "Ona jest szczęśliwa, prawda?"
                },
                {
                    "en": "Jesteś zmęczony, prawda?",
                    "ua": "Jesteś zmęczony, prawda?"
                },
                {
                    "en": "On jest lekarzem, prawda?[[[CODX_4]]]On jest lekarzem, prawda? on?",
                    "ua": "Він лікар, так?"
                },
                {
                    "en": "Oni są Brytyjczykami, prawda?",
                    "ua": "Oni są Brytyjczykami, prawda?"
                }
            ]
        },
        {
            "label": "Zdania przeczące",
            "color": "sky",
            "description": "Jeśli zdanie jest przeczące, tag staje się pozytywny:",
            "examples": [
                {
                    "en": "Ona nie jest szczęśliwa, jest ona?",
                    "ua": "Ona nie jest szczęśliwa, prawda?"
                },
                {
                    "en": "Nie jesteś zmęczony, prawda?",
                    "ua": "Nie jesteś zmęczony, prawda?"
                },
                {
                    "en": "On nie jest lekarzem, prawda?",
                    "ua": "On nie jest lekarzem doktorze, prawda?"
                },
                {
                    "en": "To nie Brytyjczycy, prawda?",
                    "ua": "To nie Brytyjczycy, prawda?"
                }
            ]
        },
        {
            "label": "Past Simple — WAS/WERE",
            "color": "purple",
            "description": "W czasie przeszłym używamy było/było:",
            "examples": [
                {
                    "en": "Było wspaniale, prawda?",
                    "ua": "Było wspaniale, prawda?"
                },
                {
                    "en": "Spóźnili się, prawda?",
                    "ua": "Spóźnili się, prawda?"
                },
                {
                    "en": "Nie było jej tam, prawda? ona?",
                    "ua": "Nie było jej tam, prawda?"
                }
            ],
            "note": "📌 Reguła: pozytywna + negatywna / negatywna + pozytywna"
        }
    ]
}

{
    "title": "3. Tagi pytań z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "blue",
            "description": "W czasie Present Simple używamy <strong>do/does</strong> w tagu:",
            "examples": [
                {
                    "en": "Lubisz kawę, prawda?",
                    "ua": "Lubisz kawę, prawda?"
                },
                {
                    "en": "Ona tu pracuje, prawda?",
                    "ua": "Ona tu pracuje, prawda?"
                },
                {
                    "en": "Mieszkają w Londynie, prawda?",
                    "ua": "Mieszkają w Londynie, prawda?"
                },
                {
                    "en": "On zna odpowiedź, prawda?",
                    "ua": "Він знає відповідь, так?"
                }
            ]
        },
        {
            "label": "Негативні речення",
            "color": "amber",
            "description": "З негативними реченнями tag позитивний:",
            "examples": [
                {
                    "en": "You don't like coffee, do you?",
                    "ua": "Тобі не подобається кава, так?"
                },
                {
                    "en": "She doesn't work here, does she?",
                    "ua": "Ona tu nie pracuje, prawda?"
                },
                {
                    "en": "Oni nie mieszkają w Londynie, prawda?",
                    "ua": "Oni nie mieszkają w Londynie, prawda?"
                }
            ]
        },
        {
            "label": "Past Simple",
            "color": "rose",
            "description": "W Past Simple używamy <strong>tak</strong>:",
            "examples": [
                {
                    "en": "Widziałeś film, prawda?",
                    "ua": "Widziałeś film, prawda?"
                },
                {
                    "en": "Zadzwoniła do ciebie, prawda?",
                    "ua": "Zadzwoniła do ciebie, prawda? ona?"
                },
                {
                    "en": "Nie przyszli, prawda? tak?",
                    "ua": "Вони не прийшли, так?"
                }
            ],
            "note": "📌 W tagu zawsze używany jest czasownik pomocniczy do/does/did"
        }
    ]
}

{
    "title": "4. Tagi pytań z czasownikami modalnymi",
    "sections": [
        {
            "label": "MOŻE / COULD / WILL / WOULD",
            "color": "emerald",
            "description": "W przypadku czasowników modalnych powtarzamy modal w tagu:",
            "examples": [
                {
                    "en": "Umiesz pływać, prawda?",
                    "ua": "Umiesz pływać, tak?"
                },
                {
                    "en": "Ona przyjdzie, prawda?",
                    "ua": "Ona przyjdzie, prawda?"
                },
                {
                    "en": "Oni mogliby pomóc, prawda?",
                    "ua": "Mogliby pomóc, prawda?"
                },
                {
                    "en": "Chciałby tego, prawda? on?",
                    "ua": " tak?"
                }
            ]
        },
        {
            "label": "POWINNO / MUSI / MOŻE",
            "color": "sky",
            "description": "Inne czasowniki modalne działają w ten sam sposób:",
            "examples": [
                {
                    "en": "Powinniśmy iść, prawda?",
                    "ua": "Powinniśmy iść, tak?"
                },
                {
                    "en": "Musisz być zmęczony, prawda?",
                    "ua": "Musisz być zmęczony, prawda?"
                },
                {
                    "en": "Ona może przyjść, prawda?",
                    "ua": "Może przyjść, prawda?"
                }
            ]
        },
        {
            "label": "Formy negatywne",
            "color": "purple",
            "description": "Z modalem ujemnym formy:",
            "examples": [
                {
                    "en": "Nie umiesz pływać, prawda?",
                    "ua": "Nie umiesz pływać, prawda?"
                },
                {
                    "en": "Ona nie przyjdzie, prawda?",
                    "ua": "Nie przyjdzie, prawda?"
                },
                {
                    "en": "Nie powinni się martwić, prawda? tak?",
                    "ua": "Їм не варто хвилюватися, так?"
                }
            ],
            "note": "📌 Czasownik modalny ze zdania powtarza się w tagu"
        }
    ]
}

{
    "title": "5. Tagi pytań z HAVE/HAS",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "amber",
            "description": "W czasie Present Perfect używamy także Have/has:",
            "examples": [
                {
                    "en": "Widziałeś film, prawda? ona?",
                    "ua": "Ти бачив цей фільм, так?"
                },
                {
                    "en": "She has finished, hasn't she?",
                    "ua": "Skończyła, prawda?"
                },
                {
                    "en": "Nie dotarły, prawda?",
                    "ua": "Nie dotarły, prawda?"
                }
            ]
        },
        {
            "label": "DOSTALI",
            "color": "blue",
            "description": "Z <strong>mają</strong> (matka) używamy tagu have/has:",
            "examples": [
                {
                    "en": "Masz samochód, prawda?",
                    "ua": "Masz samochód, prawda?"
                },
                {
                    "en": "Ona ma psa, prawda?",
                    "ua": "Ona ma psa, prawda?"
                },
                {
                    "en": "Oni nie mają czasu, prawda?",
                    "ua": "Oni nie mają czasu, prawda?"
                }
            ]
        },
        {
            "label": "Wersja amerykańska",
            "color": "rose",
            "description": "W amerykańskim angielskim słowo do jest często używane z <strong>have</strong> (mieć):",
            "examples": [
                {
                    "en": "Masz samochód, prawda?",
                    "ua": "Masz samochód, prawda? tak?"
                },
                {
                    "en": "Ona ma psa, prawda?",
                    "ua": "Ona ma psa, prawda?"
                }
            ],
            "note": "📌Wariant brytyjski: ma + nie ma/nie ma, amerykański: ma + nie ma/nie"
        }
    ]
}

{
    "title": "6. Tagi pytań z innymi czasami ",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "W Present Continuous używamy am/is/are:",
            "examples": [
                {
                    "en": "Teraz pracujesz, prawda?",
                    "ua": "Pracujesz teraz, tak?"
                },
                {
                    "en": "Ona nadchodzi, prawda? ona?",
                    "ua": "Ona wychodzi, prawda?"
                },
                {
                    "en": "Oni się nie bawią, prawda?",
                    "ua": "Nie bawią się, prawda?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "sky",
            "description": "W czasie Past Continuous używamy był/był:",
            "examples": [
                {
                    "en": "Spałeś, prawda?",
                    "ua": "Spałeś, prawda?"
                },
                {
                    "en": "Ona się uczyła, prawda?",
                    "ua": "Uczyła się, prawda?"
                },
                {
                    "en": "Oni nie oglądali telewizji, byli oni?",
                    "ua": " tak?"
                }
            ]
        },
        {
            "label": "Future Simple",
            "color": "purple",
            "description": "W Future Simple z <strong>will</strong>:",
            "examples": [
                {
                    "en": "Pomożesz mi, prawda?",
                    "ua": "Pomożesz mi, tak?"
                },
                {
                    "en": "Ona przyjdzie jutro, prawda?",
                    "ua": "Ona przyjdzie jutro, prawda?"
                },
                {
                    "en": "Nie spóźnią się, prawda?",
                    "ua": "Nie spóźnią się, prawda? oni?"
                }
            ],
            "note": "📌 Tag używa czasownika posiłkowego ze zdania"
        }
    ]
}

{
    "title": "7. Szczególne przypadki i wyjątki",
    "sections": [
        {
            "label": "JA JESTEM → NIE JESTEM?",
            "color": "rose",
            "description": "Z tagiem <strong>Jestem</strong> zawsze <strong>czyż nie jestem?</strong> (czyż nie jestem):",
            "examples": [
                {
                    "en": "Mam rację, prawda?",
                    "ua": "Jestem prawda, tak?"
                },
                {
                    "en": "Spóźniłem się, prawda?",
                    "ua": "Spóźniłem się, prawda?"
                },
                {
                    "en": "I am invited, aren't I?",
                    "ua": "Мене запросили, так?"
                }
            ]
        },
        {
            "label": "Imperatives (наказовий спосіб)",
            "color": "amber",
            "description": "З наказовим способом використовуємо <strong>will you?</strong>:",
            "examples": [
                {
                    "en": "Close the door, will you?",
                    "ua": "Zamknij drzwi, dobrze?"
                },
                {
                    "en": "Pomóż mi, dobrze?",
                    "ua": "Pomóż mi, dobrze?"
                },
                {
                    "en": "Nie spóźnij się, dobrze?[[[CODX_9]]]Nie spóźnij się, dobrze ty?",
                    "ua": "Не спізнюйся, добре?"
                }
            ]
        },
        {
            "label": "Chodźmy → BYLIŚMY?",
            "color": "blue",
            "description": "Z <strong>Let's</strong> zawsze <strong>zrobimy?</strong>:",
            "examples": [
                {
                    "en": "Chodźmy do kina, dobrze?",
                    "ua": "Zróbmy sobie przerwę, dobrze my?"
                },
                {
                    "en": "Let's have a break, shall we?",
                    "ua": "Zróbmy sobie przerwę, dobrze?"
                }
            ]
        },
        {
            "label": "TO/TANE → IT",
            "color": "emerald",
            "description": "W tagu zamiast tego/czego używamy <strong>tego</strong>:",
            "examples": [
                {
                    "en": "To jest twoja książka, prawda to?",
                    "ua": " tak?"
                },
                {
                    "en": "To było interesujące, prawda?",
                    "ua": "To było interesujące, prawda?"
                }
            ],
            "note": "📌 Specjalne zasady dla Jestem, imperatywy, zróbmy to/tamto"
        }
    ]
}

{
    "title": "8. Intonacja i użycie",
    "sections": [
        {
            "label": "Intonacja opadająca ↘",
            "color": "emerald",
            "description": "<strong>Intonacja opadająca</strong> — kiedy jesteśmy pewni i chcemy potwierdzenia:",
            "examples": [
                {
                    "en": "Ładny dzień, prawda? ↘",
                    "ua": "Miły dzień, prawda? (pewne)"
                },
                {
                    "en": "Lubisz kawę, prawda? ↘",
                    "ua": "Lubisz kawę, prawda? (znamy odpowiedź)"
                }
            ]
        },
        {
            "label": "Intonacja wznosząca ↗",
            "color": "sky",
            "description": "<strong>Intonacja wznosząca</strong> – kiedy nie jesteśmy pewni i naprawdę pytamy:",
            "examples": [
                {
                    "en": "Mieszkasz w Londynie, prawda? ↗",
                    "ua": "Mieszkasz w Londynie, prawda? (nie jestem pewien)"
                },
                {
                    "en": "Ona nadchodzi, prawda? ↗",
                    "ua": "Ona wyjeżdża, prawda? (naprawdę pytam)"
                }
            ]
        },
        {
            "label": "Użycie",
            "color": "purple",
            "description": "Tagi pytań służą do:",
            "examples": [
                {
                    "en": "Potwierdzania informacji",
                    "ua": "Potwierdzania informacji"
                },
                {
                    "en": "Rozpoczynania rozmowy",
                    "ua": "Bywania uprzejmy"
                },
                {
                    "en": "Being polite",
                    "ua": "Uprzejmość"
                },
                {
                    "en": "Okazywanie zainteresowania",
                    "ua": "Wyrażanie zainteresowania"
                }
            ],
            "note": "📌 Ważna jest intonacja: ↘ potwierdzenie, ↗ prawdziwe pytanie"
        }
    ]
}

{
    "title": "9. Tagi pytań w tabeli szybkiej tabeli",
    "intro": "Podstawowe zasady tworzenia tagów pytań:",
    "rows": [
        {
            "en": "BYĆ (am/is/are/was/were)",
            "ua": "Czasownik być",
            "note": "Ona jest szczęśliwa, prawda? / Ona nie jest szczęśliwa, prawda?"
        },
        {
            "en": "ZROBIĆ/ZROBIĆ/ZROBIĆ",
            "ua": "Proste razy",
            "note": "Podoba Ci się, prawda? / Nie podoba ci się to, prawda?"
        },
        {
            "en": "MODALS (może/będzie/powinna...)",
            "ua": "Czasowniki modalne",
            "note": "Ona potrafi pływać, prawda? / Ona nie potrafi pływać, prawda?"
        },
        {
            "en": "MA/MA (ma/idealnie)",
            "ua": "Ma i jest idealna",
            "note": "Widziałeś to, prawda?"
        },
        {
            "en": "Specjalne: ja AM",
            "ua": "Wyjątek od: Jestem",
            "note": "Mam rację, prawda? (NIE: czyż nie)"
        },
        {
            "en": "Imperatywy",
            "ua": "Imperatywy",
            "note": "Zamknij drzwi, dobrze?"
        }
    ],
    "warning": "📌 Podstawowa zasada: <strong>pozytywny + negatywny / negatywny + pozytywny</strong>"
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Ta sama forma w zdaniu i tagu.",
            "wrong": "]❌ Ona jest szczęśliwa, prawda?",
            "right": "​​​​ <span class="font-mono">Jest szczęśliwa, prawda? ona?</span>[[[CODX_6]]]Błąd 2. 3. temat w tagu."
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Неправильний tag з I am (amn't I — не існує, am I not — формальне).",
            "wrong": "❌ I am right, amn't I?",
            "right": "✅ <span class="font-mono">I am right, aren't I?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Використання do/does замість модального у tag.",
            "wrong": "❌ She can swim, doesn't she?",
            "right": "✅ <span class="font-mono">She can swim, can't she?</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Повторення повного підмета у tag.",
            "wrong": "❌ John jest szczęśliwy, prawda?",
            "right": " ✅ <span class="font-mono">John jest szczęśliwy, prawda?</span>"
        }
    ]
}

{
    "title": "12. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy tag",
    "select_intro": "Wybierz właściwy tag pytanie dla każdego zdania.",
    "selects": [
        {
            "label": "Ona jest szczęśliwa, _____? (czy ona / czy ona / czy ona nie)",
            "prompt": "Który tag jest poprawny?"
        },
        {
            "label": "Lubisz kawę, _____? (czy nie jesteś / nie jesteś / prawda)",
            "prompt": "Który tag jest poprawny?"
        },
        {
            "label": "Umieją pływać, _____? (mogą / nie mogą / nie)",
            "prompt": "Który tag jest poprawny?"
        },
        {
            "label": "Mam rację, _____? (czy nie jestem / nie jestem / czy nie jestem)",
            "prompt": "Który tag jest poprawny?"
        }
    ],
    "options": [
        "Pierwsza opcja",
        "Druga opcja",
        "Trzecia opcja"
    ],
    "input_title": "Ćwiczenie 2. Dodaj znacznik pytania",
    "input_intro": "Dodaj do zdania poprawny jeden znacznik pytania.",
    "inputs": [
        {
            "before": "Ona jest zmęczona, ",
            "after": "?"
        },
        {
            "before": "Nie lubisz herbaty, ",
            "after": "?"
        },
        {
            "before": "Może jechać, ",
            "after": "?"
        },
        {
            "before": "Nie spóźnią się. ona?",
            "after": "?"
        }
    ],
    "rephrase_title": "Вправа 3. Виправ помилки",
    "rephrase_intro": "Знайди і виправ помилку у question tag.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "She is happy, is she?",
            "example_target": "She is happy, isn't she?"
        },
        {
            "original": "1. Lubisz kawę, prawda?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Ona potrafi pływać, prawda?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Czyż nie? do tematu",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші теми з розділу Види питальних речень",
    "items": [
        {
            "label": "Yes/No Questions — Загальні питання",
            "current": false
        },
        {
            "label": "Wh-Questions — Спеціальні питання",
            "current": false
        },
        {
            "label": "Alternative Questions — Альтернативні питання",
            "current": false
        },
        {
            "label": "Subject Questions — Питання до підмета",
            "current": false
        },
        {
            "label": "Tagi pytań — pytania przekrojowe (bieżące)",
            "current": true
        }
    ]
}
